}

// Separate context for item-level state
type FormItemContextValue = { id: string }

const FormItemContext = React.createContext<FormItemContextValue>(
  {} as FormItemContextValue
)

function FormItem({ className, ...props }: React.ComponentProps<"div">) {
  const id = React.useId()

  return (
    <FormItemContext.Provider value={{ id }}>
      <div data-slot="form-item" className={cn("grid gap-2", className)} {...props} />
    </FormItemContext.Provider>
  )
}

// Sub-components use the contexts
function FormLabel({
  className,
  ...props
}: React.ComponentProps<typeof LabelPrimitive.Root>) {
  const { error, formItemId } = useFormField()

  return (
    <Label
      data-slot="form-label"
      data-error={!!error}
      className={cn("data-[error=true]:text-destructive", className)}
      htmlFor={formItemId}
      {...props}
    />
  )
}

function FormControl({ ...props }: React.ComponentProps<typeof Slot.Root>) {
  const { error, formItemId, formDescriptionId, formMessageId } = useFormField()

  return (
    <Slot.Root
      data-slot="form-control"
      id={formItemId}
      aria-describedby={!error ? `${formDescriptionId}` : `${formDescriptionId} ${formMessageId}`}
      aria-invalid={!!error}
      {...props}
    />
  )
}

function FormMessage({ className, ...props }: React.ComponentProps<"p">) {
  const { error, formMessageId } = useFormField()
  const body = error ? String(error?.message ?? "") : props.children

  if (!body) {
    return null
  }

  return (
    <p data-slot="form-message" id={formMessageId} className={cn("text-sm text-destructive", className)} {...props}>
      {body}
    </p>
  )
}

export {
  useFormField,
  Form,
  FormItem,
  FormLabel,
  FormControl,
  FormDescription,
  FormMessage,
  FormField,
}
```

**Key characteristics:**
- **Two-level context structure:**
  - `FormFieldContext` - tracks field name and state
  - `FormItemContext` - generates unique ID for accessibility
- **Custom hook pattern** - `useFormField()` encapsulates context access logic
- **Error validation** - thrown when hooks used outside provider
- **Accessibility focused** - manages aria-describedby, aria-invalid, form item IDs
- **Integration with react-hook-form** - uses `FormProvider`, `Controller`, `useFormContext`

**State sharing mechanism:**
- Nested contexts (field within item)
- Custom hooks to consume and validate context
- Integration with external form library (react-hook-form)

---

## 6. Demo/Example Structure

**Example registration format** (from `/apps/v4/registry/new-york-v4/examples/_registry.ts`):

```typescript
{
  name: "accordion-demo",
  type: "registry:example",
  registryDependencies: ["accordion"],
  files: [
    {
      path: "examples/accordion-demo.tsx",
      type: "registry:example",
    },
  ],
}
```

**Example component structure** (`accordion-demo.tsx`):

```typescript
import {
  Accordion,
  AccordionContent,
  AccordionItem,
  AccordionTrigger,
} from "@/registry/new-york-v4/ui/accordion"

export default function AccordionDemo() {
  return (
    <Accordion type="single" collapsible defaultValue="item-1">
      <AccordionItem value="item-1">
        <AccordionTrigger>Product Information</AccordionTrigger>
        <AccordionContent>
          {/* Demo content */}
        </AccordionContent>
      </AccordionItem>
    </Accordion>
  )
}
```

**Key characteristics:**
- Default export function
- Import components from registry path
- Demonstrates basic usage
- Can have multiple variants for one component

---

## 7. Registry Configuration Files

**Registry schema** (`/packages/shadcn/src/registry/schema.ts`):

```typescript
export const registryItemSchema = z.discriminatedUnion("type", [
  registryItemCommonSchema.extend({
    type: z.literal("registry:base"),
    config: rawConfigSchema.deepPartial().optional(),
  }),
  registryItemCommonSchema.extend({
    type: z.literal("registry:font"),
    font: registryItemFontSchema,
  }),
  registryItemCommonSchema.extend({
    type: registryItemTypeSchema.exclude(["registry:base", "registry:font"]),
  }),
])

export const registryItemCommonSchema = z.object({
  $schema: z.string().optional(),
  extends: z.string().optional(),
  name: z.string(),
  title: z.string().optional(),
  author: z.string().min(2).optional(),
  description: z.string().optional(),
  dependencies: z.array(z.string()).optional(),           // npm packages
  devDependencies: z.array(z.string()).optional(),        // dev npm packages
  registryDependencies: z.array(z.string()).optional(),   // other components
  files: z.array(registryItemFileSchema).optional(),
  tailwind: registryItemTailwindSchema.optional(),
  cssVars: registryItemCssVarsSchema.optional(),
  css: registryItemCssSchema.optional(),
  envVars: registryItemEnvVarsSchema.optional(),
  meta: z.record(z.string(), z.any()).optional(),
  docs: z.string().optional(),
  categories: z.array(z.string()).optional(),
})
```

**Registry item types supported:**
- `registry:ui` - UI components
- `registry:component` - Complex components
- `registry:hook` - React hooks
- `registry:block` - Full-page blocks
- `registry:page` - Pages
- `registry:example` - Demo examples
- `registry:lib` - Utility libraries
- `registry:theme` - Theme configurations
- `registry:style` - CSS styles
- `registry:base` - Base configuration
- `registry:font` - Font definitions
- `registry:file` - Static files
- `registry:internal` - Internal use

---

## Summary

This is a **monorepo-based component library** with:

1. **Core structure:**
   - Components in `/apps/v4/registry/new-york-v4/ui/` (59 components)
   - Examples in `/apps/v4/registry/new-york-v4/examples/` (100+ demo files)
   - Registry defined in TypeScript files with Zod validation

2. **Composition patterns:**
   - Named exports of sub-components (not property-based, e.g., `Accordion`, `AccordionItem` not `Accordion.Item`)
   - Heavy use of Radix UI primitives for state
   - Tailwind CSS groups for child styling based on parent state
   - `data-slot` attributes for styling hooks
   - React Context for form state sharing

3. **Registry system:**
   - Two-tier: source in `/apps/v4/registry/` and core schema in `/packages/shadcn/src/registry/schema.ts`
   - Supports dependencies, dev dependencies, and registry dependencies
   - Each component entry points to its source file(s)
   - Examples linked via `registryDependencies`

4. **No Context for most components** - state management delegated to Radix UI or external libraries (react-hook-form)

