  const { orientation } = useStepper()

  return (
    <div
      data-slot="stepper-list"
      role="tablist"
      aria-orientation={orientation}
      className={cn(
        "flex",
        orientation === "horizontal"
          ? "flex-row items-center"
          : "flex-col items-stretch",
        className
      )}
      {...props}
    />
  )
}

