"use client"

import * as React from "react"
import { CheckIcon } from "lucide-react"

import { cn } from "@/lib/utils"
import { Button } from "@/registry/new-york-v4/ui/button"
import {
  Stepper,
  StepperContent,
  StepperDescription,
  StepperItem,
  StepperList,
  StepperSeparator,
  StepperTitle,
  StepperTrigger,
} from "@/registry/new-york-v4/ui/stepper"

const STEPS = [
  {
    value: "account",
    title: "Account",
    description: "Create your account",
  },
  {
    value: "profile",
    title: "Profile",
    description: "Set up your profile",
  },
  {
    value: "billing",
    title: "Billing",
    description: "Add payment details",
  },
  {
    value: "review",
    title: "Review",
    description: "Confirm and submit",
  },
]

export default function StepperDemo() {
  const [activeStep, setActiveStep] = React.useState(STEPS[0].value)

  const currentIndex = STEPS.findIndex((s) => s.value === activeStep)

  const isCompleted = (value: string) =>
    STEPS.findIndex((s) => s.value === value) < currentIndex

  const handleNext = () => {
    if (currentIndex < STEPS.length - 1) {
      setActiveStep(STEPS[currentIndex + 1].value)
    }
  }

  const handleBack = () => {
    if (currentIndex > 0) {
      setActiveStep(STEPS[currentIndex - 1].value)
    }
  }

  return (
    <div className="w-full max-w-2xl space-y-6 px-4">
      <Stepper value={activeStep} onValueChange={setActiveStep}>
        <StepperList>
          {STEPS.map((step, index) => {
            const completed = isCompleted(step.value)
            const isLast = index === STEPS.length - 1

            return (
              <StepperItem
                key={step.value}
                value={step.value}
                completed={completed}
                className="flex-1"
              >
                <StepperTrigger>
                  <span
                    className={cn(
                      "flex size-8 shrink-0 items-center justify-center rounded-full border-2 text-xs font-semibold transition-colors",
                      activeStep === step.value || completed
                        ? "border-primary bg-primary text-primary-foreground"
                        : "border-muted-foreground/40 text-muted-foreground"
                    )}
                  >
                    {completed ? (
                      <CheckIcon className="size-4" />
                    ) : (
                      index + 1
                    )}
                  </span>
                  <div className="hidden flex-col sm:flex">
                    <StepperTitle>{step.title}</StepperTitle>
                    <StepperDescription>{step.description}</StepperDescription>
                  </div>
                </StepperTrigger>
                {!isLast && <StepperSeparator />}
              </StepperItem>
            )
          })}
        </StepperList>

        <StepperContent
          value="account"
          className="space-y-2 rounded-lg border p-6"
        >
          <h3 className="text-base font-semibold">Create your account</h3>
          <p className="text-muted-foreground text-sm">
            Enter your email address and choose a secure password to get
            started.
          </p>
        </StepperContent>

        <StepperContent
          value="profile"
          className="space-y-2 rounded-lg border p-6"
        >
          <h3 className="text-base font-semibold">Set up your profile</h3>
          <p className="text-muted-foreground text-sm">
            Add your name, avatar, and a short bio to personalize your
            experience.
          </p>
        </StepperContent>

        <StepperContent
          value="billing"
          className="space-y-2 rounded-lg border p-6"
        >
          <h3 className="text-base font-semibold">Add billing information</h3>
          <p className="text-muted-foreground text-sm">
            Your payment details are encrypted and stored securely. We never
            share them with third parties.
          </p>
        </StepperContent>

        <StepperContent
          value="review"
          className="space-y-2 rounded-lg border p-6"
        >
          <h3 className="text-base font-semibold">Review and submit</h3>
          <p className="text-muted-foreground text-sm">
            Please review all your information carefully before completing your
            setup.
          </p>
        </StepperContent>
      </Stepper>

      <div className="flex justify-between">
        <Button
          variant="outline"
          onClick={handleBack}
          disabled={currentIndex === 0}
        >
          Back
        </Button>
        <Button
          onClick={handleNext}
          disabled={currentIndex === STEPS.length - 1}
        >
          {currentIndex === STEPS.length - 2 ? "Finish" : "Next"}
        </Button>
      </div>
    </div>
  )
}

