"use client"

import * as React from "react"

import { cn } from "@/lib/utils"

// ─── Types ────────────────────────────────────────────────────────────────────

type StepperOrientation = "horizontal" | "vertical"
type StepperItemState = "active" | "completed" | "incomplete"

// ─── Stepper Context ──────────────────────────────────────────────────────────

type StepperContextValue = {
  value: string
  onValueChange: (value: string) => void
  orientation: StepperOrientation
}

const StepperContext = React.createContext<StepperContextValue | null>(null)

function useStepper() {
  const context = React.useContext(StepperContext)
  if (!context) {
    throw new Error("useStepper must be used within a <Stepper />")
  }
  return context
}

// ─── StepperItem Context ──────────────────────────────────────────────────────

type StepperItemContextValue = {
  value: string
  state: StepperItemState
  disabled: boolean
}

const StepperItemContext =
  React.createContext<StepperItemContextValue | null>(null)

function useStepperItem() {
  const context = React.useContext(StepperItemContext)
  if (!context) {
    throw new Error("useStepperItem must be used within a <StepperItem />")
  }
  return context
}

// ─── Stepper ──────────────────────────────────────────────────────────────────

type StepperProps = React.ComponentProps<"div"> & {
  /** The controlled active step value. */
  value?: string
  /** The default active step value (uncontrolled). */
  defaultValue?: string
  /** Callback fired when the active step changes. */
  onValueChange?: (value: string) => void
  /** Layout orientation of the stepper. @default "horizontal" */
  orientation?: StepperOrientation
}

function Stepper({
  value: valueProp,
  defaultValue = "",
  onValueChange,
  orientation = "horizontal",
  className,
  ...props
}: StepperProps) {
  const [internalValue, setInternalValue] = React.useState(defaultValue)

  const isControlled = valueProp !== undefined
  const value = isControlled ? valueProp : internalValue

  const handleValueChange = React.useCallback(
    (newValue: string) => {
      if (!isControlled) {
        setInternalValue(newValue)
      }
      onValueChange?.(newValue)
    },
    [isControlled, onValueChange]
  )

  return (
    <StepperContext.Provider
      value={{ value, onValueChange: handleValueChange, orientation }}
    >
      <div
        data-slot="stepper"
        data-orientation={orientation}
        className={cn(
          "group/stepper flex",
          orientation === "horizontal" ? "flex-col gap-4" : "flex-row gap-6",
          className
        )}
        {...props}
      />
    </StepperContext.Provider>
  )
}

// ─── StepperList ──────────────────────────────────────────────────────────────

/**
 * Wraps all `StepperItem` children and applies the correct flex direction and
 * ARIA `tablist` role. Place this directly inside `<Stepper>`.
 */
function StepperList({ className, ...props }: React.ComponentProps<"div">) {
  const { orientation } = useStepper()

  return (
    <div
      data-slot="stepper-list"
      role="tablist"
      aria-orientation={orientation}
      className={cn(
        "flex",
        orientation === "horizontal"
          ? "flex-row items-center"
          : "flex-col items-stretch",
        className
      )}
      {...props}
    />
  )
}

// ─── StepperItem ──────────────────────────────────────────────────────────────

type StepperItemProps = React.ComponentProps<"div"> & {
  /** Unique identifier for this step, matched against the stepper's active value. */
  value: string
  /**
   * Mark this step as completed. When `true` and the step is not active the
   * state is set to `"completed"`, which turns the separator primary-coloured.
   */
  completed?: boolean
  /** Prevents the trigger from being clicked. */
  disabled?: boolean
}

function StepperItem({
  value,
  completed = false,
  disabled = false,
  className,
  ...props
}: StepperItemProps) {
  const { value: stepperValue, orientation } = useStepper()

  const state: StepperItemState =
    stepperValue === value
      ? "active"
      : completed
        ? "completed"
        : "incomplete"

  return (
    <StepperItemContext.Provider value={{ value, state, disabled }}>
      <div
        data-slot="stepper-item"
        data-state={state}
        data-orientation={orientation}
        data-disabled={disabled ? "" : undefined}
        className={cn(
          "group/stepper-item flex items-center",
          orientation === "horizontal" ? "flex-row" : "flex-col",
          className
        )}
        {...props}
      />
    </StepperItemContext.Provider>
  )
}

// ─── StepperTrigger ───────────────────────────────────────────────────────────

function StepperTrigger({
  className,
  disabled: disabledProp,
  ...props
}: React.ComponentProps<"button">) {
  const { onValueChange } = useStepper()
  const { value, state, disabled: itemDisabled } = useStepperItem()

  const isDisabled = disabledProp ?? itemDisabled

  return (
    <button
      type="button"
      role="tab"
      data-slot="stepper-trigger"
      data-state={state}
      data-disabled={isDisabled ? "" : undefined}
      disabled={isDisabled}
      aria-selected={state === "active"}
      aria-current={state === "active" ? "step" : undefined}
      aria-disabled={isDisabled}
      className={cn(
        "group/stepper-trigger inline-flex shrink-0 items-center gap-2 rounded-md px-1.5 py-1 text-start transition-colors",
        "hover:bg-accent hover:text-accent-foreground",
        "focus-visible:ring-ring/50 focus-visible:outline-none focus-visible:ring-[3px]",
        "disabled:pointer-events-none disabled:opacity-50",
        className
      )}
      onClick={() => onValueChange(value)}
      {...props}
    />
  )
}

// ─── StepperTitle ─────────────────────────────────────────────────────────────

function StepperTitle({ className, ...props }: React.ComponentProps<"p">) {
  return (
    <p
      data-slot="stepper-title"
      className={cn("text-sm font-medium leading-none", className)}
      {...props}
    />
  )
}

// ─── StepperDescription ───────────────────────────────────────────────────────

function StepperDescription({
  className,
  ...props
}: React.ComponentProps<"p">) {
  return (
    <p
      data-slot="stepper-description"
      className={cn("text-muted-foreground text-sm", className)}
      {...props}
    />
  )
}

// ─── StepperSeparator ────────────────────────────────────────────────────────

/**
 * Visual connector between two steps. Reflects its parent `StepperItem`'s
 * state: when `completed` the line turns `primary`-coloured.
 *
 * Place it **inside** a `<StepperItem>` so it inherits the item's state via
 * context. For horizontal layouts the separator grows to fill the remaining
 * space between triggers; for vertical layouts it draws a thin vertical line
 * below the trigger.
 */
function StepperSeparator({
  className,
  ...props
}: React.ComponentProps<"div">) {
  const { orientation } = useStepper()
  const itemContext = React.useContext(StepperItemContext)
  const state = itemContext?.state

  return (
    <div
      data-slot="stepper-separator"
      data-state={state}
      aria-hidden="true"
      className={cn(
        "rounded-full bg-border transition-colors data-[state=completed]:bg-primary",
        orientation === "horizontal"
          ? "h-px min-w-8 flex-1"
          : "ms-4 min-h-6 w-px flex-1 self-stretch",
        className
      )}
      {...props}
    />
  )
}

// ─── StepperContent ──────────────────────────────────────────────────────────

type StepperContentProps = React.ComponentProps<"div"> & {
  /**
   * The step value this panel belongs to. Can be omitted when
   * `<StepperContent>` is placed directly inside a `<StepperItem>`, in which
   * case the value is read from the parent item's context.
   */
  value?: string
}

/**
 * Panel rendered only when its step is active.
 *
 * Can be used in two ways:
 * - **Inside `<StepperItem>`** — omit the `value` prop; it is read from context.
 * - **Outside `<StepperItem>`, inside `<Stepper>`** — pass an explicit `value` prop.
 */
function StepperContent({
  value: valueProp,
  className,
  ...props
}: StepperContentProps) {
  const { value: stepperValue } = useStepper()
  const itemContext = React.useContext(StepperItemContext)

  const targetValue = valueProp ?? itemContext?.value

  if (!targetValue || targetValue !== stepperValue) {
    return null
  }

  return (
    <div
      data-slot="stepper-content"
      role="tabpanel"
      className={cn("flex-1", className)}
      {...props}
    />
  )
}

// ─── Exports ──────────────────────────────────────────────────────────────────

export {
  Stepper,
  StepperList,
  StepperItem,
  StepperTrigger,
  StepperTitle,
  StepperDescription,
  StepperSeparator,
  StepperContent,
  useStepper,
  useStepperItem,
}
